import React, { useState, useEffect, useCallback } from "react";
import { useNavigate } from "react-router-dom";
import { useAuth }  from "../context/AuthContext";
import { useObras } from "../context/ObraContext";
import Header       from "../components/Layout/Header";
import Sidebar      from "../components/Layout/Sidebar";
import Footer       from "../components/Layout/Footer";
import CardResumen  from "../components/Cards/CardResumen";
import Button       from "../components/Shared/Button";
import OrchestradorPanel from "../components/OrchestradorPanel";
import { controlAPI } from "../utils/api";

export default function Dashboard() {
  const navigate          = useNavigate();
  const { user }          = useAuth();
  const { stats, loading } = useObras();

  const [ahora,          setAhora]     = useState(new Date());
  const [sistemaInfo,    setSistema]   = useState(null); // datos reales del backend
  const [loadingSistema, setLoadSist]  = useState(true);

  /* Reloj en vivo */
  useEffect(() => {
    const id = setInterval(() => setAhora(new Date()), 1000);
    return () => clearInterval(id);
  }, []);

  /* Estado real del sistema desde el backend */
  useEffect(() => {
    setLoadSist(true);
    controlAPI.getEstado()
      .then((res) => setSistema(res))
      .catch(() => setSistema(null))
      .finally(() => setLoadSist(false));
  }, []);

  const sistemaAbierto = sistemaInfo
    ? sistemaInfo.abierto
    : ahora.getHours() < 12; // fallback local si el backend no responde

  const horaFormateada = ahora.toLocaleTimeString("es-CL", {
    hour: "2-digit", minute: "2-digit", second: "2-digit",
  });

  const tiempoRestante = sistemaInfo?.tiempoRestanteMinutos;
  const formatearRestante = () => {
    if (!tiempoRestante || tiempoRestante <= 0) return null;
    const h = Math.floor(tiempoRestante / 60);
    const m = tiempoRestante % 60;
    return h > 0 ? `${h}h ${m}m` : `${m}m`;
  };

  const handleVerObras = useCallback(() => navigate("/obras"), [navigate]);

  if (loading) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-gray-50">
        <div className="text-center">
          <div className="w-8 h-8 border-4 border-primary-500 border-t-transparent rounded-full animate-spin mx-auto mb-3" />
          <p className="text-sm text-gray-500">Cargando...</p>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen flex flex-col bg-gray-50">
      <Header />

      <div className="flex flex-1">
        <Sidebar />

        <main className="flex-1 px-4 sm:px-6 lg:px-8 py-6 max-w-6xl mx-auto w-full">

          {/* Saludo + estado sistema */}
          <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-4 mb-8 animate-fade-in">
            <div>
              <h1 className="text-2xl font-bold text-gray-800">
                Bienvenido, {user?.nombre || "Administrador"} 👋
              </h1>
              <p className="text-gray-500 text-sm mt-1">
                {ahora.toLocaleDateString("es-CL", {
                  weekday: "long", day: "numeric", month: "long", year: "numeric",
                })}
              </p>
            </div>

            {/* Indicador sistema */}
            <div className={`flex items-center gap-3 px-4 py-3 rounded-xl border
              ${sistemaAbierto ? "bg-green-50 border-green-200" : "bg-red-50 border-red-200"}`}>
              <div className="text-center">
                <div className={`flex items-center gap-2 text-sm font-semibold
                  ${sistemaAbierto ? "text-green-700" : "text-red-600"}`}>
                  <span className={`w-2.5 h-2.5 rounded-full ${sistemaAbierto ? "bg-green-500 animate-pulse" : "bg-red-400"}`} />
                  {loadingSistema ? "Verificando..." : sistemaAbierto ? "SISTEMA ABIERTO" : "SISTEMA CERRADO"}
                </div>
                <p className="text-xs text-gray-500 mt-0.5 font-mono">{horaFormateada}</p>
                {sistemaAbierto && formatearRestante() && (
                  <p className="text-xs text-green-600 mt-0.5">Cierra en {formatearRestante()}</p>
                )}
                {sistemaInfo?.periodo_actual && (
                  <p className="text-xs text-gray-400 mt-0.5">{sistemaInfo.periodo_actual}</p>
                )}
              </div>
            </div>
          </div>

          {/* Cards de resumen */}
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4 mb-8">
            <CardResumen
              titulo="Total de obras"
              valor={stats.total}
              subtitulo="Obras registradas"
              icono="🏗️"
              colorClase="text-gray-800"
              bgClase="bg-gray-100"
            />
            <CardResumen
              titulo="Actualizadas"
              valor={stats.actualizadas}
              subtitulo={`${stats.pct}% del total`}
              icono="✅"
              colorClase="text-primary-600"
              bgClase="bg-primary-50"
            />
            <CardResumen
              titulo="Pendientes"
              valor={stats.pendientes}
              subtitulo={`${stats.total - stats.actualizadas} sin actualizar`}
              icono="⏳"
              colorClase="text-red-500"
              bgClase="bg-red-50"
            />
          </div>

          {/* Barra de progreso global */}
          <div className="bg-white rounded-2xl border border-gray-200 shadow-sm p-6 mb-8 animate-fade-in">
            <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-2 mb-4">
              <div>
                <h2 className="font-semibold text-gray-800">Progreso del corte actual</h2>
                <p className="text-sm text-gray-500">
                  {stats.actualizadas} de {stats.total} obras actualizadas
                </p>
              </div>
              <span className="text-3xl font-bold text-primary-600">{stats.pct}%</span>
            </div>

            <div className="w-full bg-gray-100 rounded-full h-4 overflow-hidden">
              <div
                className="h-4 rounded-full bg-gradient-to-r from-primary-500 to-teal-400 transition-all duration-700"
                style={{ width: `${stats.pct}%` }}
              />
            </div>

            <div className="flex justify-between text-xs text-gray-400 mt-2">
              <span>0%</span>
              <span className={`font-medium ${
                stats.pct >= 80 ? "text-green-600" :
                stats.pct >= 50 ? "text-yellow-600" : "text-red-500"
              }`}>
                {stats.pct >= 80 ? "Buen avance" : stats.pct >= 50 ? "En progreso" : "Requiere atención"}
              </span>
              <span>100%</span>
            </div>
          </div>

          {/* Distribución por estado */}
          <div className="grid grid-cols-1 sm:grid-cols-3 gap-4 mb-8">
            {[
              { label: "Actualizadas", valor: stats.actualizadas, color: "bg-green-500",
                pct: stats.total ? Math.round(stats.actualizadas / stats.total * 100) : 0 },
              { label: "En progreso",  valor: stats.enProgreso,   color: "bg-teal-400",
                pct: stats.total ? Math.round(stats.enProgreso   / stats.total * 100) : 0 },
              { label: "Pendientes",   valor: stats.pendientes,   color: "bg-red-400",
                pct: stats.total ? Math.round(stats.pendientes   / stats.total * 100) : 0 },
            ].map(({ label, valor, color, pct }) => (
              <div key={label} className="bg-white rounded-xl border border-gray-200 p-4 shadow-sm">
                <div className="flex items-center justify-between mb-2">
                  <span className="text-sm text-gray-600">{label}</span>
                  <span className="font-bold text-gray-800">{valor}</span>
                </div>
                <div className="w-full bg-gray-100 rounded-full h-1.5">
                  <div className={`h-1.5 rounded-full ${color}`} style={{ width: `${pct}%` }} />
                </div>
                <p className="text-xs text-gray-400 mt-1">{pct}%</p>
              </div>
            ))}
          </div>

          {/* Asistente de consultas */}
          <div className="mb-8 animate-fade-in">
            <OrchestradorPanel />
          </div>

          {/* CTA */}
          <div className="bg-gradient-to-r from-primary-600 to-teal-500 rounded-2xl p-6 text-white
            flex flex-col sm:flex-row items-center justify-between gap-4 animate-fade-in">
            <div>
              <h3 className="font-bold text-lg">Ver todas las obras</h3>
              <p className="text-teal-100 text-sm mt-1">
                Accede al listado completo y actualiza el avance de cada obra.
              </p>
            </div>
            <Button
              variant="secondary"
              size="lg"
              onClick={handleVerObras}
              className="shrink-0"
              aria-label="Ir al listado completo de obras"
            >
              Ver obras →
            </Button>
          </div>

        </main>
      </div>

      <Footer />
    </div>
  );
}
